mapper.select:
SELECT COUNT(1)
FROM im_message m
JOIN im_conversation_user cu ON cu.conversation_id = m.conversation_id
JOIN im_conversation c ON c.id = m.conversation_id
WHERE m.conversation_id = #{conversationId}
  AND cu.user_id = #{userId}
  AND cu.deleted = 0
  AND c.status = 1
  AND m.seq_no > #{afterSeq}

SELECT MAX(seq_no)
FROM im_message
WHERE conversation_id = #{conversationId}
